def is_valid_position(pos):
    return 0 <= pos[0] < 8 and 0 <= pos[1] < 8

def is_opponent_piece(piece, player):
    if piece is None:
        return False
    return (player == 'white' and piece.islower()) or (player == 'black' and piece.isupper())
