### Step 5: Implement `is_valid_move` in `game.py`

```python
def is_valid_move(self, start_pos, end_pos):
    if not is_valid_position(start_pos) or not is_valid_position(end_pos):
        return False

    piece = self.board.board[start_pos[0]][start_pos[1]]
    if piece is None or piece.lower() != self.current_player:
        return False

    target_piece = self.board.board[end_pos[0]][end_pos[1]]
    if target_piece and not is_opponent_piece(target_piece, self.current_player):
        return False

    # Add logic for specific moves based on the type of piece
    if piece.islower():
        return self._is_valid_pawn_move(start_pos, end_pos)
    elif piece.isupper():
        return self._is_valid_king_move(start_pos, end_pos)

    return False
```

### Step 6: Implement `_is_valid_pawn_move` and `_is_valid_king_move` in `game.py`

```python
def _is_valid_pawn_move(self, start_pos, end_pos):
    if abs(end_pos[0] - start_pos[0]) == 1 and abs(end_pos[1] - start_pos[1]) == 1:
        return True
    elif self.current_player == 'white' and start_pos[0] == 6 and end_pos[0] == 4:
        return end_pos[1] == start_pos[1]
    elif self.current_player == 'black' and start_pos[0] == 1 and end_pos[0] == 3:
        return end_pos[1] == start_pos[1]
    else:
        return False

def _is_valid_king_move(self, start_pos, end_pos):
    row_diff = abs(end_pos[0] - start_pos[0])
    col_diff = abs(end_pos[1] - start_pos[1])
    if (row_diff == 1 and col_diff == 1) or (row_diff == 2 and col_diff == 2):
        return True
    else:
        return False
```

### Step 7: Implement `check_game_over` in `game.py`

