def check_game_over(self):
    # Check for kinging condition
    if any(cell.upper() == 'K' for row in self.board.board for cell in row):
        print(f"{self.current_player.capitalize()} has won by kings!")
        self.game_over = True
        return

    # Check for no valid moves left
    for i in range(8):
        for j in range(8):
            if self.board.board[i][j] and self.board.board[i][j].lower() == self.current_player:
                for di, dj in [(-1, -1), (-1, 1), (1, -1), (1, 1)]:
                    ni, nj = i + 2 * di, j + 2 * dj
                    if is_valid_position(ni, nj) and self.is_valid_move((i, j), (ni, nj)):
                        return False

    print(f"{self.current_player.capitalize()} has no valid moves. Game over!")
    self.game_over = True
    return True
```

